use clap::{Parser, Subcommand, ValueEnum};
use std::collections::HashMap;
use std::path::PathBuf;

use crate::{api, config::Config, error::Result};

#[derive(Parser)]
#[command(
    name = "templateflow",
    version,
    about = "TemplateFlow Rust CLI - Access neuroimaging templates",
    long_about = "Access a library of standard reference anatomical atlases for \
                  neuroimaging organized according to the Brain Imaging Data Structure (BIDS)"
)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Commands,
}

#[derive(Subcommand)]
pub enum Commands {
    /// List available templates or files within a template
    Ls {
        /// Template name (if not provided, lists all templates)
        template: Option<String>,

        /// Resolution level (e.g., 1, 2)
        #[arg(short, long)]
        resolution: Option<u32>,

        /// File suffix (e.g., T1w, brain_mask)
        #[arg(short, long)]
        suffix: Option<String>,

        /// Atlas name
        #[arg(short, long)]
        atlas: Option<String>,

        /// Hemisphere (L or R)
        #[arg(long)]
        hemisphere: Option<String>,

        /// Space (e.g., MNI152NLin2009cAsym)
        #[arg(long)]
        space: Option<String>,

        /// Density
        #[arg(short, long)]
        density: Option<String>,

        /// Description
        #[arg(long)]
        description: Option<String>,

        /// File extension (e.g., .nii.gz)
        #[arg(short, long)]
        extension: Option<String>,
    },

    /// Download template files
    Get {
        /// Template name
        template: String,

        /// Resolution level (e.g., 1, 2)
        #[arg(short, long)]
        resolution: Option<u32>,

        /// File suffix (e.g., T1w, brain_mask)
        #[arg(short, long)]
        suffix: Option<String>,

        /// Atlas name
        #[arg(short, long)]
        atlas: Option<String>,

        /// Hemisphere (L or R)
        #[arg(long)]
        hemisphere: Option<String>,

        /// Space (e.g., MNI152NLin2009cAsym)
        #[arg(long)]
        space: Option<String>,

        /// Density
        #[arg(short, long)]
        density: Option<String>,

        /// Description
        #[arg(long)]
        description: Option<String>,

        /// File extension (e.g., .nii.gz)
        #[arg(short, long)]
        extension: Option<String>,

        /// Force re-download even if file exists
        #[arg(short, long)]
        force: bool,
    },

    /// Show configuration settings
    Config {
        /// Show all configuration values
        #[arg(short, long)]
        all: bool,

        /// Show specific configuration key
        key: Option<ConfigKey>,
    },

    /// Update the template skeleton index
    Update {
        /// Skip confirmation prompt
        #[arg(short = 'y', long)]
        yes: bool,
    },

    /// Clear the local cache
    Wipe {
        /// Skip confirmation prompt
        #[arg(short = 'y', long)]
        yes: bool,

        /// Only remove files for specific template
        #[arg(short, long)]
        template: Option<String>,
    },
}

#[derive(Clone, ValueEnum)]
pub enum ConfigKey {
    /// Cache home directory
    Home,
    /// S3 root URL
    S3Root,
    /// Auto-update setting
    Autoupdate,
    /// Request timeout
    Timeout,
}

impl Cli {
    pub async fn run() -> Result<()> {
        let cli = Self::parse();

        match cli.command {
            Commands::Ls { template, resolution, suffix, atlas, hemisphere, space, density, description, extension } => {
                let mut query = HashMap::new();

                if let Some(res) = resolution {
                    query.insert("resolution".to_string(), res.to_string());
                }
                if let Some(s) = suffix {
                    query.insert("suffix".to_string(), s);
                }
                if let Some(a) = atlas {
                    query.insert("atlas".to_string(), a);
                }
                if let Some(h) = hemisphere {
                    query.insert("hemisphere".to_string(), h);
                }
                if let Some(sp) = space {
                    query.insert("space".to_string(), sp);
                }
                if let Some(d) = density {
                    query.insert("density".to_string(), d);
                }
                if let Some(desc) = description {
                    query.insert("description".to_string(), desc);
                }
                if let Some(ext) = extension {
                    query.insert("extension".to_string(), ext);
                }

                if let Some(tpl) = template {
                    // List files in a specific template
                    let files = api::ls(&tpl, query)?;
                    if files.is_empty() {
                        println!("No files found matching the query");
                    } else {
                        for file in files {
                            println!("{}", file.display());
                        }
                    }
                } else {
                    // List all templates
                    let templates = api::templates(query)?;
                    if templates.is_empty() {
                        println!("No templates found");
                    } else {
                        for template in templates {
                            println!("{}", template);
                        }
                    }
                }
            }

            Commands::Get { template, resolution, suffix, atlas, hemisphere, space, density, description, extension, force } => {
                let mut query = HashMap::new();

                if let Some(res) = resolution {
                    query.insert("resolution".to_string(), res.to_string());
                }
                if let Some(s) = suffix {
                    query.insert("suffix".to_string(), s);
                }
                if let Some(a) = atlas {
                    query.insert("atlas".to_string(), a);
                }
                if let Some(h) = hemisphere {
                    query.insert("hemisphere".to_string(), h);
                }
                if let Some(sp) = space {
                    query.insert("space".to_string(), sp);
                }
                if let Some(d) = density {
                    query.insert("density".to_string(), d);
                }
                if let Some(desc) = description {
                    query.insert("description".to_string(), desc);
                }
                if let Some(ext) = extension {
                    query.insert("extension".to_string(), ext);
                }

                // TODO: Add force parameter support once API supports it
                let _ = force; // Suppress unused warning for now

                let files = api::get(&template, query)?;
                if files.is_empty() {
                    println!("No files downloaded");
                } else {
                    println!("Downloaded {} file(s):", files.len());
                    for file in files {
                        println!("  {}", file.display());
                    }
                }
            }

            Commands::Config { all, key } => {
                let config = Config::new();

                if all || key.is_none() {
                    println!("TemplateFlow Configuration:");
                    println!("  Home: {}", config.home.display());
                    println!("  S3 Root: {}", config.s3_root);
                    println!("  Auto-update: {}", config.autoupdate);
                    println!("  Timeout: {:?}", config.timeout);
                } else if let Some(k) = key {
                    match k {
                        ConfigKey::Home => println!("{}", config.home.display()),
                        ConfigKey::S3Root => println!("{}", config.s3_root),
                        ConfigKey::Autoupdate => println!("{}", config.autoupdate),
                        ConfigKey::Timeout => println!("{:?}", config.timeout),
                    }
                }
            }

            Commands::Update { yes } => {
                if !yes {
                    println!("This will update the template skeleton index.");
                    print!("Continue? [y/N] ");
                    use std::io::{self, Write};
                    io::stdout().flush()?;

                    let mut input = String::new();
                    io::stdin().read_line(&mut input)?;

                    if !input.trim().eq_ignore_ascii_case("y") {
                        println!("Update cancelled.");
                        return Ok(());
                    }
                }

                println!("Updating template skeleton...");
                crate::s3::update_skeleton()?;
                println!("Template skeleton updated successfully.");
            }

            Commands::Wipe { yes, template } => {
                let cache = crate::cache::Cache::new()?;

                if !yes {
                    if let Some(ref tpl) = template {
                        println!("This will remove all cached files for template '{}'.", tpl);
                    } else {
                        println!("This will remove ALL cached template files.");
                    }
                    print!("Continue? [y/N] ");
                    use std::io::{self, Write};
                    io::stdout().flush()?;

                    let mut input = String::new();
                    io::stdin().read_line(&mut input)?;

                    if !input.trim().eq_ignore_ascii_case("y") {
                        println!("Wipe cancelled.");
                        return Ok(());
                    }
                }

                if let Some(tpl) = template {
                    // Clear specific template
                    let files = cache.get_template_files(&tpl);
                    let count = files.len();
                    for file in files {
                        cache.remove_file(&file)?;
                    }
                    println!("Removed {} cached file(s) for template '{}'.", count, tpl);
                } else {
                    // Clear all
                    cache.clear()?;
                    println!("Cache cleared successfully.");
                }

                // Clean up empty directories
                cache.cleanup_empty_dirs()?;
            }
        }

        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use clap::CommandFactory;

    #[test]
    fn verify_cli() {
        Cli::command().debug_assert();
    }
}

