                    println!("  S3 Root: {}", config.s3_root);
                    println!("  Auto-update: {}", config.autoupdate);
                    println!("  Timeout: {:?}", config.timeout);
                } else if let Some(k) = key {
                    match k {
                        ConfigKey::Home => println!("{}", config.home.display()),
                        ConfigKey::S3Root => println!("{}", config.s3_root),
                        ConfigKey::Autoupdate => println!("{}", config.autoupdate),
                        ConfigKey::Timeout => println!("{:?}", config.timeout),
                    }
                }
            }

            Commands::Update { yes } => {
                if !yes {
                    println!("This will update the template skeleton index.");
                    print!("Continue? [y/N] ");
                    use std::io::{self, Write};
                    io::stdout().flush()?;

                    let mut input = String::new();
                    io::stdin().read_line(&mut input)?;

                    if !input.trim().eq_ignore_ascii_case("y") {
                        println!("Update cancelled.");
                        return Ok(());
                    }
                }

                println!("Updating template skeleton...");
                crate::s3::update_skeleton()?;
                println!("Template skeleton updated successfully.");
            }

            Commands::Wipe { yes, template } => {
                let cache = crate::cache::Cache::new()?;

                if !yes {
                    if let Some(ref tpl) = template {
                        println!("This will remove all cached files for template '{}'.", tpl);
                    } else {
                        println!("This will remove ALL cached template files.");
                    }
                    print!("Continue? [y/N] ");
                    use std::io::{self, Write};
                    io::stdout().flush()?;

                    let mut input = String::new();
                    io::stdin().read_line(&mut input)?;

                    if !input.trim().eq_ignore_ascii_case("y") {
                        println!("Wipe cancelled.");
                        return Ok(());
                    }
                }

                if let Some(tpl) = template {
                    // Clear specific template
                    let files = cache.get_template_files(&tpl);
                    let count = files.len();
                    for file in files {
                        cache.remove_file(&file)?;
                    }
                    println!("Removed {} cached file(s) for template '{}'.", count, tpl);
                } else {
                    // Clear all
                    cache.clear()?;
                    println!("Cache cleared successfully.");
                }

                // Clean up empty directories
                cache.cleanup_empty_dirs()?;
            }
        }

        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use clap::CommandFactory;

    #[test]
    fn verify_cli() {
        Cli::command().debug_assert();
    }
}

